import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface FeedingSchedule {
  morning: string;
  afternoon: string;
  evening: string;
}

interface VetAppointment {
  date: string;
  time: string;
  vetName: string;
  location: string;
}

interface ActivityLevel {
  day: string;
  level: string;
}

interface PetCareData {
  petName: string;
  feedingSchedule: FeedingSchedule;
  nextVetAppointment: VetAppointment;
  activityLevel: ActivityLevel[];
}

export default function Widget() {
  const petCareData = response.data as PetCareData;
  const { petName, feedingSchedule, nextVetAppointment, activityLevel } = petCareData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              {petName}'s Care Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Feeding Schedule
            </Typography>
            <Stack direction="row" spacing={2} sx={{ mt: 0.5 }}>
              <Typography variant="body2">{`Morning: ${feedingSchedule.morning}`}</Typography>
              <Typography variant="body2">{`Afternoon: ${feedingSchedule.afternoon}`}</Typography>
              <Typography variant="body2">{`Evening: ${feedingSchedule.evening}`}</Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Next Vet Appointment
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              {`${nextVetAppointment.date} at ${nextVetAppointment.time} with ${nextVetAppointment.vetName}, ${nextVetAppointment.location}`}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Weekly Activity Level
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: activityLevel.map(d => d.level === "High" ? 3 : d.level === "Moderate" ? 2 : 1),
                  color: '#FFC107',
                },
              ]}
              xAxis={[
                {
                  data: activityLevel.map(d => d.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              yAxis={[
                {
                  scaleType: 'linear',
                  tickFormat: (value) => ["Low", "Moderate", "High"][value - 1],
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
